'use client';

import ProtectedRoute from '@/components/ProtectedRoute';
import Layout from '@/components/Layout';
import { useEffect, useState } from 'react';
import axios from 'axios';

export const dynamic = 'force-dynamic';

export default function AdminDashboard() {
  const [stats, setStats] = useState({ products: 0, posts: 0, orders: 0 });

  useEffect(() => {
    axios.get('/api/admin/products').then(res => setStats(prev => ({ ...prev, products: res.data.length })));
    axios.get('/api/admin/daily-posts').then(res => setStats(prev => ({ ...prev, posts: res.data.length })));
    // orders would need an API endpoint
  }, []);

  return (
    <ProtectedRoute>
      <Layout title="Admin Dashboard">
        <div className="p-8">
          <h1 className="text-3xl font-bold mb-6">Admin Dashboard</h1>
          <div className="grid grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded shadow"><h2>Products</h2><p className="text-2xl">{stats.products}</p></div>
            <div className="bg-white p-6 rounded shadow"><h2>Daily Posts</h2><p className="text-2xl">{stats.posts}</p></div>
            <div className="bg-white p-6 rounded shadow"><h2>Orders</h2><p className="text-2xl">{stats.orders}</p></div>
          </div>
        </div>
      </Layout>
    </ProtectedRoute>
  );
}